// Called when we have just connected to an AP (we are a STAtion) and have a valid IP
// Called when we are a functional AP (we've manually started it)
void glue_wifi_on_connect(struct mg_tcpip_if *ifp) {
  struct mg_wifi_data *wifi = (struct mg_wifi_data *) ifp->driver_data;

  // If we are a STA, we successfully connected (4/4: select network; 2/2: connect)
    if (!wifi->apmode) MG_INFO(("READY!"));
    // CONNECTING --> READY
    if (!wifi->apmode) return; // for normal functioning consistency

  // If we are an AP, we don't need to do anything.
    // (2/2: start AP)
    MG_INFO(("Access Point READY !"));

    // When, as part of our configuration process, a user connects to our HTTP server and requests a network scan:
    {
      bool res = mg_wifi_scan();
      MG_INFO(("Starting scan: %s", res ? "OK":"FAIL"));
      // success =>  AP --> SCANNING
    }
}

