// Called when we disconnect from an AP (we are a STAtion)
// Called when we no longer are an AP (we've shut it down)
void glue_wifi_on_disconnect(struct mg_tcpip_if *ifp) {
  struct mg_wifi_data *wifi = (struct mg_wifi_data *) ifp->driver_data;

  // If we are a STA, and we successfully disconnected because we wanted to
    // (2/2: disconnect)

  // If we are a STA, but we did not intend to disconnect, we might want to retry:
    // so, connect as above (1/2: connect)
    if (!wifi->apmode) return; // for normal functioning consistency

  // If we are an AP, we have successfully stopped it
    // (2/2: stop AP)
    wifi->apmode = false;
    // This is usually (2/4: select network), when, as part of our configuration process, a user connected to our HTTP server requests to connect to a network (maybe after a network scan):
    // so, we connect as above (3/4: select network)
      // STOPPING_AP --> CONNECTING
    // if that call fails, though, we might want to start the AP again, as above (1/2: start AP)
      // STOPPING_AP --> AP
}


// Called when we failed to connect to an AP (we are a STAtion), or get an IP through DHCP
void glue_wifi_on_connect_error(struct mg_tcpip_if *ifp) {
  MG_ERROR(("Wi-Fi connect failed"));

  // If we are a STA and just want to connect, we might want to retry, as above
    // stay CONNECTING 

  // If we were an AP and were just trying that network out of a series of choices in our configuration process, we might want to start the AP again, as above
    // CONNECTING --> AP

  (void) ifp;
}

// Called for every BSSID found (we've manually started a network scan)
void glue_wifi_on_scan_result(struct mg_tcpip_if *ifp, struct mg_wifi_scan_bss_data *bss) {
  MG_INFO(("BSS: %.*s (%u) (%M) %d dBm %u", bss->SSID.len, bss->SSID.buf, bss->channel, mg_print_mac, bss->BSSID, (int) bss->RSSI, bss->security));
  (void) ifp;
}

// Called when there are no more networks, glue_wifi_on_scan_result() won't be called again until we manually start another scan
void glue_wifi_on_scan_end(struct mg_tcpip_if *ifp) {
  MG_INFO(("Scan ended"));
  // SCANNING --> AP
  (void) ifp;
}

